import{_ as t,H as a,f as o,i as s}from"./chunks/framework.nN4pLK1d.js";const u=JSON.parse('{"title":"Switches","description":"","frontmatter":{},"headers":[],"relativePath":"packages/rcml/email/concepts/advanced/switches.md","filePath":"packages/rcml/email/concepts/advanced/switches.md"}'),c={name:"packages/rcml/email/concepts/advanced/switches.md"};function n(r,e,i,l,d,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1>Switches</h1><p><code>&lt;rc-switch&gt;</code> lets different email content be shown to different recipients based on their tags, segments, or custom field values — without creating separate templates. All the content variants live in one document; the renderer picks one at send time.</p><p>Without switches, showing different content to different audiences requires maintaining separate templates — one for VIP members, one for regular subscribers, one for lapsed users. Any structural change, like a new footer or an updated header, has to be applied to every variant. A switch puts all variants in one document: one place to update, one version to track in version control.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p><code>rc-switch</code> holds one or more <code>rc-case</code> children. At send time, the renderer evaluates the cases top to bottom and renders the first one whose condition matches the recipient. A <code>case-type=&quot;default&quot;</code> case provides the fallback when nothing else matches. If there is no default and no condition matches, <code>rc-switch</code> renders nothing.</p><p>Each <code>rc-case</code> wraps exactly one <code>rc-section</code>, so every branch can contain a full row of content.</p><h2 id="practical-uses" tabindex="-1">Practical uses <a class="header-anchor" href="#practical-uses" aria-label="Permalink to &quot;Practical uses&quot;">​</a></h2><p>Common applications: showing a discount offer only to subscribers with a specific tag; rendering a language-specific greeting based on a subscriber custom field; displaying a loyalty-tier benefit section for members above a certain spending threshold and hiding it for everyone else.</p><p>The <code>default</code> case is important: without it, any recipient who doesn&#39;t match a condition sees a blank space where the switch is — not an error, just silence. Always include a default case unless an empty section is intentional.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/control-flow/rc-switch.html"><code>&lt;rc-switch&gt;</code> reference</a> — attributes, condition types, and examples</li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/control-flow/rc-case.html"><code>&lt;rc-case&gt;</code> reference</a></li></ul>',11)])])}const m=t(c,[["render",n]]);export{u as __pageData,m as default};
